stack<int> s;

int cnt = 1;
int cntscc = 0;

void dfs(int node) {
    ind[node] = lowlink[node] = cnt++;
    instack[node] = 1;
    s.push(node);
    for(auto x : g[node]){
        if (ind[x] == 0) {
            dfs(x);
            lowlink[node] = min(lowlink[node], lowlink[x]);
        }
        else if (instack[x]) lowlink[node] = min(lowlink[node], ind[x]);
    }
    if (ind[node] == lowlink[node]) {
        while(!s.empty()) {
            auto a = s.top(); s.pop();
            scc[a] = cntscc;
            instack[a] = 0;
            if (a == node) break;
        }
        cntscc++;
    }
}

